-- Enable pgvector extension
CREATE EXTENSION IF NOT EXISTS vector;

-- ==================== TABLE STRUCTURES ====================

-- Table: customers
DROP TABLE IF EXISTS customers CASCADE;
CREATE TABLE customers (
    id integer NOT NULL DEFAULT nextval('customers_id_seq'::regclass),
    name character varying(100) NOT NULL,
    company character varying(200),
    phone character varying(20),
    email character varying(100),
    address character varying(500),
    longitude double precision,
    latitude double precision,
    status character varying(20),
    source character varying(50),
    remark character varying(1000),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);

-- Table: deals
DROP TABLE IF EXISTS deals CASCADE;
CREATE TABLE deals (
    id integer NOT NULL DEFAULT nextval('deals_id_seq'::regclass),
    customer_id bigint,
    opportunity_id bigint,
    title character varying(200) NOT NULL,
    amount numeric,
    contract_date date,
    status character varying(20),
    remark character varying(1000),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);

-- Table: follow_ups
DROP TABLE IF EXISTS follow_ups CASCADE;
CREATE TABLE follow_ups (
    id integer NOT NULL DEFAULT nextval('follow_ups_id_seq'::regclass),
    customer_id bigint NOT NULL,
    content character varying(2000) NOT NULL,
    type character varying(20),
    next_follow_up_date date,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);

-- Table: knowledge_docs
DROP TABLE IF EXISTS knowledge_docs CASCADE;
CREATE TABLE knowledge_docs (
    id integer NOT NULL DEFAULT nextval('knowledge_docs_id_seq'::regclass),
    content character varying(5000) NOT NULL,
    customer_id bigint,
    embedding vector(1024),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    title character varying(255),
    category character varying(100),
    PRIMARY KEY (id)
);

-- Table: leads
DROP TABLE IF EXISTS leads CASCADE;
CREATE TABLE leads (
    id integer NOT NULL DEFAULT nextval('leads_id_seq'::regclass),
    customer_id bigint,
    source character varying(50),
    status character varying(20),
    score integer,
    remark character varying(1000),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    name character varying(100),
    company character varying(200),
    phone character varying(50),
    email character varying(100),
    PRIMARY KEY (id)
);

-- Table: opportunities
DROP TABLE IF EXISTS opportunities CASCADE;
CREATE TABLE opportunities (
    id integer NOT NULL DEFAULT nextval('opportunities_id_seq'::regclass),
    customer_id bigint,
    title character varying(200) NOT NULL,
    amount numeric,
    stage character varying(20),
    probability integer,
    expected_close_date date,
    remark character varying(1000),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);

-- Table: system_config
DROP TABLE IF EXISTS system_config CASCADE;
CREATE TABLE system_config (
    id bigint NOT NULL DEFAULT nextval('system_config_id_seq'::regclass),
    config_key character varying(100) NOT NULL,
    config_value text,
    description character varying(255),
    category character varying(50),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);

-- Table: users
DROP TABLE IF EXISTS users CASCADE;
CREATE TABLE users (
    id integer NOT NULL DEFAULT nextval('users_id_seq'::regclass),
    username character varying(50) NOT NULL,
    password character varying(200) NOT NULL,
    real_name character varying(100),
    role character varying(20) DEFAULT 'user'::character varying,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);


